// Compile all data into briefing context
const healthRaw = $input.all()[0]?.json?.stdout || '{}';
const systemRaw = $input.all()[1]?.json?.stdout || '{}';
const emails = $input.all()[2]?.json || {};
const weatherData = $input.all()[3]?.json || {};

let health, system;
try { health = JSON.parse(healthRaw); } catch { health = { status: 'PARSE_ERROR' }; }
try { system = JSON.parse(systemRaw); } catch { system = {}; }

// Count unread emails
const unreadCount = Array.isArray(emails) ? emails.length : (emails.resultSizeEstimate || 0);

// Format weather
let weatherStr = 'Weather data unavailable';
if (weatherData.main) {
  weatherStr = `${Math.round(weatherData.main.temp)}F, ${weatherData.weather?.[0]?.description || 'unknown'}, High ${Math.round(weatherData.main.temp_max)}F / Low ${Math.round(weatherData.main.temp_min)}F`;
}

const briefingData = {
  date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
  health: health,
  system: system,
  unreadEmails: unreadCount,
  weather: weatherStr,
  weatherRaw: weatherData
};

return [{ json: briefingData }];

